// src/pages/Reservation.jsx
import React from 'react';

export default function Reservation() {
  return (
    <div style={styles.container}>
      <form style={styles.form}>
        <h2 style={styles.title}>Réservation de salle</h2>
        <input type="text" placeholder="Nom de la salle" style={styles.input} />
        <input type="date" style={styles.input} />
        <input type="time" placeholder="Heure de début" style={styles.input} />
        <input type="time" placeholder="Heure de fin" style={styles.input} />
        <button type="submit" style={styles.button}>Réserver</button>
      </form>
    </div>
  );
}

const styles = {
  container: {
    minHeight: '100vh',
    background: 'linear-gradient(120deg, #43cea2, #185a9d)',
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    padding: 20,
  },
  form: {
    backgroundColor: '#ffffff',
    padding: '35px 25px',
    borderRadius: '12px',
    boxShadow: '0 10px 30px rgba(0,0,0,0.1)',
    width: '100%',
    maxWidth: '420px',
    display: 'flex',
    flexDirection: 'column',
    gap: '16px',
  },
  title: {
    marginBottom: '10px',
    textAlign: 'center',
    color: '#222',
  },
  input: {
    padding: '12px',
    border: '1px solid #ccc',
    borderRadius: '8px',
    fontSize: '15px',
  },
  button: {
    padding: '12px',
    backgroundColor: '#43cea2',
    color: 'white',
    fontWeight: 'bold',
    borderRadius: '8px',
    border: 'none',
    cursor: 'pointer',
    transition: 'background 0.3s',
  },
};
